arguments.argument:
/*
Vault Gate script.
This will move the player to the Vault.
*/
if global.gamePaused=false
{
  if global.gameProgress>=2170
  {
    if oKeyCodesHighFPS.kCodePressed[3]=1
    {
      resetKeyCodes()
      global.recAreaTrans+=1
      global.rmDeaths=0
      global.newMapX=160
      global.newMapY=288
      writeToPlayerGlobals()
      
      transition_steps=20
      transition_kind=21
      room_goto_fixed(rVault_1)
    }
  }
  else //First time going into the Vault
  {
    global.gamePaused=true
    global.gameProgress=2160
  }
}
